const input = $input.first().json;
return {
  product: input.product,
  hsCode: input.hsCode,
  value: parseFloat(input.value),
  origin: input.origin,
  destination: input.destination,
  weight: parseFloat(input.weight)
};

const shipment = $input.all()[0].json;
const tariff = $input.all()[1].json;

// Extract tariff rate (handle various formats)
let dutyRate = 0;
if (tariff && tariff.rate) {
  if (typeof tariff.rate === 'string' && tariff.rate.includes('%')) {
    dutyRate = parseFloat(tariff.rate) / 100;
  } else {
    dutyRate = tariff.rate || 0;
  }
}

// Calculate duties
const fobValue = shipment.value;
const freight = shipment.value * 0.1; // 10% freight estimate
const insurance = shipment.value * 0.005; // 0.5% insurance
const cif = fobValue + freight + insurance;

const importDuty = cif * dutyRate;
const processingFee = Math.max(25, cif * 0.002); // 0.2% or $25 min
const mpf = Math.min(485, cif * 0.0021); // Merchandise processing fee
const hmf = fobValue * 0.00125; // Harbor maintenance fee

const totalDuty = importDuty + processingFee + mpf + hmf;

return {
  shipment,
  tariffRate: (dutyRate * 100).toFixed(2) + '%',
  calculations: {
    fobValue: fobValue.toFixed(2),
    freight: freight.toFixed(2),
    insurance: insurance.toFixed(2),
    cif: cif.toFixed(2),
    importDuty: importDuty.toFixed(2),
    processingFee: processingFee.toFixed(2),
    mpf: mpf.toFixed(2),
    hmf: hmf.toFixed(2),
    totalDuty: totalDuty.toFixed(2)
  }
};

const calc = $input.all()[0].json;
const fta = $input.all()[1].json;

let savings = 0;
let notes = [];

if (fta && fta.agreement) {
  const discount = parseFloat(fta.discount) || 0;
  savings = calc.calculations.importDuty * discount;
  notes.push(`FTA: ${fta.agreement} - ${discount * 100}% reduction`);
}

return {
  ...calc,
  fta: fta || { agreement: 'None' },
  savings: savings.toFixed(2),
  finalDuty: (calc.calculations.totalDuty - savings).toFixed(2),
  notes
};

const calc = $input.first().json;

// US de minimis thresholds
const thresholds = {
  'US': 800,  // $800 for personal shipments
  'CA': 40,
  'MX': 50,
  'UK': 135
};

const dest = calc.shipment.destination.toUpperCase();
const threshold = thresholds[dest] || 100;
const value = parseFloat(calc.shipment.value);

let deMinimis = false;
let notes = [];

if (value <= threshold) {
  deMinimis = true;
  notes.push(`✓ Below de minimis ($${threshold}) - No duties required`);
}

return {
  ...calc,
  deMinimis,
  threshold,
  notes: [...calc.notes, ...notes]
};
